// src/components/Forecast.jsx
import React from "react";

const forecastData = [
  { day: "Mon", temp: "33°C", condition: "☀️ Sunny" },
  { day: "Tue", temp: "30°C", condition: "🌧 Rain" },
  { day: "Wed", temp: "29°C", condition: "🌥 Cloudy" },
  { day: "Thu", temp: "31°C", condition: "⛈ Thunder" },
  { day: "Fri", temp: "28°C", condition: "🌦 Showers" },
  { day: "Sat", temp: "27°C", condition: "☁️ Overcast" },
  { day: "Sun", temp: "34°C", condition: "☀️ Sunny" },
  { day: "Mon", temp: "32°C", condition: "☀️ Sunny" },
  { day: "Tue", temp: "30°C", condition: "🌧 Rain" },
  { day: "Wed", temp: "29°C", condition: "🌥 Cloudy" },
  { day: "Thu", temp: "31°C", condition: "⛈ Thunder" },
  { day: "Fri", temp: "28°C", condition: "🌦 Showers" },
  { day: "Sat", temp: "27°C", condition: "☁️ Overcast" },
  { day: "Sun", temp: "34°C", condition: "☀️ Sunny" },
];

export default function Forecast() {
  return (
    <div className="min-h-screen bg-black text-white p-6">
      <h1 className="text-2xl font-bold mb-4">16-Day Forecast</h1>
      <div className="grid grid-cols-2 sm:grid-cols-4 lg:grid-cols-7 gap-4">
        {forecastData.map((day, idx) => (
          <div
            key={idx}
            className="bg-white/10 backdrop-blur-md p-4 rounded-xl shadow-lg ring-1 ring-white/20"
          >
            <p className="text-sm">{day.day}</p>
            <p className="text-lg font-bold">{day.temp}</p>
            <p className="text-sm text-white/80">{day.condition}</p>
          </div>
        ))}
      </div>
    </div>
  );
}
